function detectScopeItems(s){const a=String(s||"").toLowerCase(),r=[{key:"tear_off",label:"Tear off existing shingles",costLow:300,costHigh:800,patterns:[/tear.?off/,/remove existing/,/replace.?existing/,/strip existing/,/remov(?:e|al).*(?:old|existing|current).*roof/,/replace.*(?:old|existing|current).*roof/,/roof(?:ing)?\s+remov/,/replac.*roof/,/remov.*roof/,/new.*(?:asphalt|shingle|roof)/,/(?:asphalt|shingle).*replac/]},{key:"underlayment",label:"Underlayment",costLow:200,costHigh:600,patterns:[/underlayment/,/felt paper/,/synthetic underlayment/,/ice.*water.*shield/,/weather\s*lock/,/deck\s*armor/,/deck\s*defense/,/tiger\s*paw/,/roof\s*deck\s*protect/]},{key:"drip_edge",label:"Drip edge",costLow:100,costHigh:300,patterns:[/drip edge/,/drip\s*edge/,/edge\s*metal/,/eave\s*metal/]},{key:"flashing",label:"Flashing replacement",costLow:200,costHigh:600,patterns:[/flashing/,/flash\s*ing/,/step flash/,/counter flash/,/wall flash/,/chimney flash/,/pipe flash/,/roof flash/,/damaged flash/,/repair.*flash/,/flash.*repair/,/new flash/,/fl\s*ash/]},{key:"ice_barrier",label:"Ice and water barrier",costLow:150,costHigh:500,patterns:[/ice.?water/,/ice barrier/,/ice shield/,/weather\s*lock/,/storm\s*guard/,/leak\s*barrier/]},{key:"ridge_vent",label:"Ridge ventilation",costLow:150,costHigh:450,patterns:[/ridge vent/,/ridge ventilation/,/ventilation/,/vent(?:s|ing|ilation)?\b/,/exhaust vent/,/attic vent/,/roof vent/,/additional ventilation/,/install.*vent/,/vent\s*il/,/v\s*e\s*n\s*t/,/turbine/,/soffit vent/]},{key:"starter",label:"Starter shingles",costLow:75,costHigh:200,patterns:[/starter shingle/,/starter strip/,/starter course/,/eave starter/]},{key:"ridge_cap",label:"Ridge cap shingles",costLow:100,costHigh:350,patterns:[/ridge cap/,/hip.*cap/,/cap shingle/]},{key:"valley_metal",label:"Valley metal",costLow:100,costHigh:400,patterns:[/valley metal/,/metal valley/,/valley/,/open valley/,/woven valley/]},{key:"deck_repair",label:"Deck repair allowance",costLow:200,costHigh:1e3,patterns:[/deck(?:ing)?\s*repair/,/replace plywood/,/replace osb/,/rotten.*(?:wood|deck|board|plywood|sheet)/,/damaged.*(?:wood|deck|board|framework|roof)/,/repair.*(?:wood|deck|framework|plywood|board|roof\s*framework)/,/(?:wood|deck|plywood|osb)\s*repair/,/per\s*sheet/,/roof\s*(?:deck|sheathing)/,/roof\s*framework/,/framework/,/damag.*framework/,/damag.*roof/]},{key:"disposal",label:"Debris disposal",costLow:150,costHigh:500,patterns:[/dumpster/,/debris remov/,/haul away/,/disposal/,/clean.?up/,/dispose/,/waste remov/,/dump fee/]},{key:"permit",label:"Permit included",costLow:100,costHigh:400,patterns:[/permit/,/inspection/,/building permit/,/code complian/]}],t=[];for(const o of r){const i=o.patterns.some(e=>e.test(a));t.push({key:o.key,label:o.label,detected:i,costLow:o.costLow,costHigh:o.costHigh})}return t}function calculateScopeScore(s){const a=s.length,r=s.filter(e=>e.detected).length,t=s.filter(e=>!e.detected),o=t.reduce((e,l)=>e+(l.costLow||0),0),i=t.reduce((e,l)=>e+(l.costHigh||0),0);return{detected:r,total:a,score:Math.round(r/a*100),missingCount:t.length,missingCostLow:o,missingCostHigh:i,missingItems:t}}window.detectScopeItems=detectScopeItems,window.calculateScopeScore=calculateScopeScore;
